    def process(self, payload: Dict[str, Any], raw_message: Dict[str, Any]) -> None:
        message_type = payload.get("type")
        if not message_type:
            raise ValueError("Message missing required field: type")

        handler = self._handlers.get(message_type)
        if not handler:
            raise ValueError(f"No handler registered for message type: {message_type}")

